import numpy as np

def algo(initial_population, individual_upper, individual_lower, objective_function):
    population = initial_population.copy()
    num_individuals, num_variables = population.shape
    evaluations = 0
    best_solution = np.copy(population[0])
    best_objective = float('inf')
    memory = []
    stagnation_count = 0
    max_evaluations = 60000
    max_stagnation = 50
    diversity_threshold = 1e-5

    def adaptive_reinitialization():
        return np.clip(np.random.uniform(individual_lower, individual_upper, population.shape), individual_lower, individual_upper)

    def hybrid_mutation(i):
        indices = list(range(num_individuals))
        indices.remove(i)
        a, b, c = np.random.choice(indices, 3, replace=False)
        mutation_factor = np.clip(np.random.uniform(0.1, 0.6), 0.1, 0.6)
        return population[a] + mutation_factor * (population[b] - population[c])

    def perform_local_search(solution):
        return simulated_annealing_search(gradient_based_local_search(solution))

    def gradient_based_local_search(solution):
        epsilon = 1e-6
        step_size = 0.1
        f_current = objective_function(solution)
        for _ in range(10):
            gradients = np.zeros(num_variables)
            for j in range(num_variables):
                perturb = np.zeros(num_variables)
                perturb[j] = epsilon
                f_plus = objective_function(np.clip(solution + perturb, individual_lower, individual_upper))
                f_minus = objective_function(np.clip(solution - perturb, individual_lower, individual_upper))
                gradients[j] = (f_plus - f_minus) / (2 * epsilon)
            new_solution = np.clip(solution - step_size * gradients, individual_lower, individual_upper)
            if objective_function(new_solution) < f_current:
                solution = new_solution
                f_current = objective_function(new_solution)
        return solution

    def simulated_annealing_search(solution):
        f_current = objective_function(solution)
        temperature = 1.0
        cooling_rate = 0.95
        while temperature > 1e-3:
            perturbation = np.random.uniform(-0.1, 0.1, num_variables)
            new_solution = np.clip(solution + perturbation, individual_lower, individual_upper)
            f_new = objective_function(new_solution)
            if f_new < f_current or np.random.rand() < np.exp((f_current - f_new) / temperature):
                solution = new_solution
                f_current = f_new
            temperature *= cooling_rate
        return solution

    def manage_memory():
        if len(memory) > memory_size:
            memory.sort(key=objective_function)
            memory = memory[:memory_size]

    def diversity_measure(pop):
        return np.std([objective_function(ind) for ind in pop])

    while evaluations < max_evaluations:
        if stagnation_count > max_stagnation:
            population = adaptive_reinitialization()
            stagnation_count = 0

        current_best = best_objective

        for i in range(num_individuals):
            if evaluations >= max_evaluations:
                break
            mutant = hybrid_mutation(i)
            trial = np.copy(population[i])
            for j in range(num_variables):
                if np.random.rand() < 0.5:
                    trial[j] = mutant[j]

            f_trial = objective_function(trial)
            evaluations += 1

            if f_trial < best_objective:
                best_objective = f_trial
                best_solution = trial

            if f_trial < objective_function(population[i]):
                population[i] = trial
                if f_trial < best_objective:
                    memory.append(trial)
                    manage_memory()

        unique_memory = np.array(list({tuple(x) for x in memory}))

        for mem_solution in unique_memory:
            local_candidate = perform_local_search(np.array(mem_solution))
            f_local = objective_function(local_candidate)
            evaluations += 1

            if f_local < best_objective:
                best_objective = f_local
                best_solution = local_candidate

        if diversity_measure(population) < diversity_threshold:
            stagnation_count += 1
        else:
            stagnation_count = 0

    return best_solution
